func TestNovelInboxHealthCountsGenericEmailUnread(t *testing.T) {
	db := openTestStore(t)
	defer db.Close()

	receivedAt := time.Now().Add(-2 * time.Hour).UTC().Format(time.RFC3339)
	insertTestResource(t, db, "emails", "email-1", map[string]any{
		"id":          "email-1",
		"direction":   "inbound",
		"status":      "unread",
		"received_at": receivedAt,
		"thread_id":   "thread-1",
	})

	flags := &rootFlags{asJSON: true}
	cmd := newNovelInboxHealthCmd(flags)
	var out bytes.Buffer
	cmd.SetOut(&out)
	cmd.SetErr(&bytes.Buffer{})

	if err := cmd.Execute(); err != nil {
		t.Fatalf("execute inbox health: %v", err)
	}

	var got struct {
		Mailboxes []struct {
			MailboxID       string `json:"mailbox_id"`
			UnreadCount     int    `json:"unread_count"`
			OldestUnread    string `json:"oldest_unread"`
			OldestUnreadAge string `json:"oldest_unread_age"`
		} `json:"mailboxes"`
	}
	if err := json.Unmarshal(out.Bytes(), &got); err != nil {
		t.Fatalf("decode output: %v\n%s", err, out.String())
	}
	if len(got.Mailboxes) != 1 {
		t.Fatalf("mailboxes len = %d, want 1: %#v", len(got.Mailboxes), got.Mailboxes)
	}
	if got.Mailboxes[0].MailboxID != "unknown" {
		t.Fatalf("mailbox_id = %q, want unknown", got.Mailboxes[0].MailboxID)
	}
	if got.Mailboxes[0].UnreadCount != 1 {
		t.Fatalf("unread_count = %d, want 1", got.Mailboxes[0].UnreadCount)
	}
	if got.Mailboxes[0].OldestUnread != receivedAt {
		t.Fatalf("oldest_unread = %q, want %q", got.Mailboxes[0].OldestUnread, receivedAt)
	}
	if got.Mailboxes[0].OldestUnreadAge == "" {
		t.Fatalf("oldest_unread_age was empty")
	}
}

